#!/usr/bin/env node
import { access, mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const root =
  process.env.API_RESOURCE_ROOT ??
  dirname(dirname(fileURLToPath(import.meta.url)));
const generatedHeader =
  "// GENERATED by generate-api-resource.mjs; DO NOT EDIT\n";
const operations = new Set(["list", "get", "create", "update", "remove"]);
const collectionOperations = new Map([
  ["list", "GET"],
  ["create", "POST"],
]);
const detailOperations = new Map([
  ["get", "GET"],
  ["update", "PATCH"],
  ["remove", "DELETE"],
]);

function assertSlug(value, label) {
  if (typeof value !== "string" || !/^[a-z][a-z0-9-]*$/.test(value)) {
    throw new Error(`Invalid ${label}: ${String(value)}`);
  }
}

function assertDisplayName(value) {
  if (typeof value !== "string" || value.trim() === "") {
    throw new Error(`Invalid displayName: ${String(value)}`);
  }
}

function pascalCase(value) {
  return value
    .split("-")
    .map((part) => part[0].toUpperCase() + part.slice(1))
    .join("");
}

function identifier(value) {
  return value.replace(/-([a-z])/g, (_, letter) => letter.toUpperCase());
}

function validate(resource) {
  ["name", "group", "route", "resourceType"].forEach((key) =>
    assertSlug(resource[key], key)
  );
  assertDisplayName(resource.displayName);
  if (!Array.isArray(resource.operations) || resource.operations.length === 0) {
    throw new Error(`${resource.name} must declare at least one operation.`);
  }
  resource.operations.forEach((operation) => {
    if (!operations.has(operation)) {
      throw new Error(`Invalid operation: ${operation}`);
    }
  });
  if (new Set(resource.operations).size !== resource.operations.length) {
    throw new Error(`${resource.name} declares duplicate operations.`);
  }
}

function clientTemplate(resource) {
  const name = pascalCase(resource.name);
  const type = `${name}Resource`;
  const supports = resource.operations
    .map((operation) => JSON.stringify(operation))
    .join(", ");
  return `${generatedHeader}import { createResourceClient } from "../../api/client";

export interface ${type} {
  readonly id: string;
  readonly type: string;
  readonly attributes: Record<string, unknown>;
}

export interface ${name}ListQuery
  extends Record<string, string | number | undefined> {
  readonly cursor?: string;
  readonly pageSize?: number;
  readonly sort?: string;
}

export type Create${name}Request = Record<string, unknown>;
export type Update${name}Request = Record<string, unknown>;

export const ${identifier(resource.name)}Client = createResourceClient<
  unknown,
  ${name}ListQuery,
  Create${name}Request,
  Update${name}Request,
  ${type}
>({
  path: "/api/${resource.route}",
  supports: [${supports}],
});
`;
}

function operationTemplate(operation, detail) {
  const method = (detail ? detailOperations : collectionOperations).get(
    operation
  );
  if (method == null) return undefined;
  const parse = detail ? " parse: parseDetailPath," : "";
  return `    ${method}: {${parse} execute: () => Promise.resolve(notImplemented) },`;
}

function hooksTemplate(resource) {
  const name = identifier(resource.name);
  const message = JSON.stringify(`${resource.displayName} is not implemented.`);
  const collectionMethods = resource.operations
    .map((operation) => operationTemplate(operation, false))
    .filter((operation) => operation != null)
    .join("\n");
  const detailMethods = resource.operations
    .map((operation) => operationTemplate(operation, true))
    .filter((operation) => operation != null)
    .join("\n");
  const collectionSpec =
    collectionMethods === ""
      ? ""
      : `\nexport const ${name}CollectionRouteSpec: VertexRouteSpec<unknown, unknown, ErrorRes> = {\n  operations: {\n${collectionMethods}\n  },\n};\n`;
  const detailSpec =
    detailMethods === ""
      ? ""
      : `\ninterface DetailInput {\n  readonly id: string;\n}\n\nfunction parseDetailPath(req: NextIronRequest): DetailInput | ErrorRes {\n  const id = requiredPathParam(req, "id");\n  return typeof id === "string" ? { id } : id;\n}\n\nexport const ${name}DetailRouteSpec: VertexRouteSpec<DetailInput, unknown, ErrorRes> = {\n  operations: {\n${detailMethods}\n  },\n};\n`;
  return `// developer-owned: generated once and never overwritten
import { type ErrorRes } from "../../api/contracts";
import { requiredPathParam, type VertexRouteSpec } from "../../api/route";
import { type NextIronRequest } from "../../with-session";

// Replace these placeholders with typed SDK calls and resource-specific lifecycle overrides.
const notImplemented: ErrorRes = { message: ${message}, status: 501 };
${collectionSpec}${detailSpec}`;
}

function routeTemplate(resource, detail) {
  const name = pascalCase(resource.name);
  const hook = `${identifier(resource.name)}${
    detail ? "Detail" : "Collection"
  }RouteSpec`;
  const relative = detail ? "../../../lib" : "../../lib";
  const handler = `handle${name}${detail ? "Detail" : ""}`;
  return `${generatedHeader}import { createVertexRoute } from "${relative}/api/route";
import { ${hook} } from "${relative}/resources/${resource.group}/${resource.name}.hooks";
import withSession from "${relative}/with-session";

export const ${handler} = createVertexRoute(
  ${hook}
);
export default withSession(${handler});
`;
}

function resourceFiles(resource) {
  const resourceRoot = join("src", "lib", "resources", resource.group);
  const files = new Map([
    [
      join(resourceRoot, `${resource.name}.client.ts`),
      clientTemplate(resource),
    ],
  ]);
  if (
    resource.operations.some((operation) => collectionOperations.has(operation))
  ) {
    files.set(
      join("src", "pages", "api", `${resource.route}.ts`),
      routeTemplate(resource, false)
    );
  }
  if (
    resource.operations.some((operation) => detailOperations.has(operation))
  ) {
    files.set(
      join("src", "pages", "api", resource.route, "[id].ts"),
      routeTemplate(resource, true)
    );
  }
  return files;
}

function hooksPath(resource) {
  return join(
    "src",
    "lib",
    "resources",
    resource.group,
    `${resource.name}.hooks.ts`
  );
}

function validateManifest(resources) {
  const names = new Set();
  const routes = new Set();
  const paths = new Set();
  for (const resource of resources) {
    validate(resource);
    if (names.has(resource.name))
      throw new Error(`Duplicate resource name: ${resource.name}`);
    if (routes.has(resource.route))
      throw new Error(`Duplicate route: ${resource.route}`);
    names.add(resource.name);
    routes.add(resource.route);
    for (const path of [
      ...resourceFiles(resource).keys(),
      hooksPath(resource),
    ]) {
      if (paths.has(path)) throw new Error(`Duplicate generated path: ${path}`);
      paths.add(path);
    }
  }
}

async function fileExists(path) {
  try {
    await access(path);
    return true;
  } catch {
    return false;
  }
}

async function readExisting(absolutePath) {
  return (await fileExists(absolutePath))
    ? readFile(absolutePath, "utf8")
    : undefined;
}

function assertGeneratedOwner(relativePath, existing) {
  if (existing != null && !existing.startsWith(generatedHeader)) {
    throw new Error(
      `Refusing to overwrite non-generated file: ${relativePath}`
    );
  }
}

async function main() {
  const args = process.argv.slice(2);
  const check = args.includes("--check");
  const resourceIndex = args.indexOf("--resource");
  if (resourceIndex !== -1 && args[resourceIndex + 1] == null) {
    throw new Error("--resource requires a name.");
  }
  const manifest = JSON.parse(
    await readFile(join(root, "api-resources.json"), "utf8")
  );
  if (!Array.isArray(manifest.resources)) {
    throw new Error("api-resources.json must have a resources array.");
  }
  validateManifest(manifest.resources);
  const selected =
    resourceIndex === -1
      ? manifest.resources
      : manifest.resources.filter(
          (item) => item.name === args[resourceIndex + 1]
        );
  if (selected.length === 0) {
    throw new Error("No matching resource in api-resources.json.");
  }

  const resourceOutputs = await Promise.all(
    selected.map(async (resource) => {
      const generated = await Promise.all(
        [...resourceFiles(resource)].map(async ([relativePath, content]) => {
          const absolutePath = join(root, relativePath);
          const existing = await readExisting(absolutePath);
          assertGeneratedOwner(relativePath, existing);
          return { absolutePath, content, existing, relativePath };
        })
      );
      const relativePath = hooksPath(resource);
      return {
        generated,
        hook: {
          absolutePath: join(root, relativePath),
          content: hooksTemplate(resource),
          existing: await readExisting(join(root, relativePath)),
          relativePath,
        },
      };
    })
  );
  const generated = resourceOutputs.flatMap((output) => output.generated);
  const hooks = resourceOutputs.map((output) => output.hook);

  const drift = [
    ...generated
      .filter(({ content, existing }) => content !== existing)
      .map(({ relativePath }) => relativePath),
    ...hooks
      .filter(({ existing }) => existing == null)
      .map(({ relativePath }) => relativePath),
  ];
  if (check) {
    if (drift.length > 0) {
      throw new Error(
        `Generated files are out of date:\n${drift
          .map((path) => ` - ${path}`)
          .join("\n")}`
      );
    }
    return;
  }

  await Promise.all(
    generated
      .filter(({ content, existing }) => content !== existing)
      .map(async ({ absolutePath, content }) => {
        await mkdir(dirname(absolutePath), { recursive: true });
        await writeFile(absolutePath, content);
      })
  );
  await Promise.all(
    hooks
      .filter(({ existing }) => existing == null)
      .map(async ({ absolutePath, content }) => {
        await mkdir(dirname(absolutePath), { recursive: true });
        await writeFile(absolutePath, content);
      })
  );
}

main().catch((error) => {
  console.error(error.message);
  process.exitCode = 1;
});
